function solve(points) {
    const MOD = 10**9 + 7;
    const inv2 = 500000004;
    const freq = new Map();

    for (const [x, y] of points) {
        const count = freq.get(y) || 0;
        freq.set(y, count + 1);
    }

    let total_sum = 0;
    let sum_squares = 0;

    for (const [y, count] of freq.entries()) {
        const term = count * (count - 1);
        const term_mod = term % MOD;
        const term_div = (term_mod * inv2) % MOD;
        total_sum = (total_sum + term_div) % MOD;

        const term_sq = (term_div * term_div) % MOD;
        sum_squares = (sum_squares + term_sq) % MOD;
    }

    const numerator = ((total_sum * total_sum % MOD - sum_squares) % MOD + MOD) % MOD;
    const ans = (numerator * inv2) % MOD;

    return ans;
}
